        public HttpResponseData getDeviceStatus(String deviceIp) throws IOException {
            HttpRequest request = new HttpRequest.Builder()
                    .url("http://" + deviceIp + "/status")
                    .method("GET")
                    .networkTarget(NetworkTarget.LOCAL_DEVICE)
                    .build();
            return client.execute(request);
        }

        public HttpResponseData setDeviceConfig(String deviceIp, Map<String, Object> configValues) throws IOException {
            HttpRequest request = new HttpRequest.Builder()
                    .url("http://" + deviceIp + "/config")
                    .method("POST")
                    .contentType("application/json; charset=utf-8")
                    .body(SimpleJson.jsonBody(configValues))
                    .networkTarget(NetworkTarget.LOCAL_DEVICE)
                    .build();
            return client.execute(request);
        }

        public HttpResponseData fetchCloudDevices(String bearerToken) throws IOException {
            HttpRequest request = new HttpRequest.Builder()
                    .url(cloudBaseUrl + "/devices")
                    .method("GET")
                    .header("Authorization", "Bearer " + bearerToken)
                    .networkTarget(NetworkTarget.CLOUD_API)
                    .build();
            return client.execute(request);
        }

        public HttpResponseData updateCloudDevice(String bearerToken, String deviceId, Map<String, Object> payload) throws IOException {
            HttpRequest request = new HttpRequest.Builder()
                    .url(cloudBaseUrl + "/devices/" + deviceId)
                    .method("PUT")
                    .header("Authorization", "Bearer " + bearerToken)
                    .contentType("application/json; charset=utf-8")
                    .body(SimpleJson.jsonBody(payload))
                    .networkTarget(NetworkTarget.CLOUD_API)
                    .build();
            return client.execute(request);
        }
